    if (!range.offset(0, -1).getValue()) {
      range.offset(0, -1).setValue(new Date());
    }
  }

  // Severity validation
  if (range.getColumn() === 3) {
    const severity = parseInt(e.value);
    if (isNaN(severity) || severity < 1 || severity > 10) {
      SpreadsheetApp.getUi().alert('Severity must be 1-10');
      range.setValue('');
    }
  }
}
